{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT DISTINCT \\\"Listing Exchange\\\" FROM stockinfo;\"",
  "description": "Check distinct listing exchanges"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT DISTINCT ETF FROM stockinfo;\"",
  "description": "Check ETF values"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT COUNT(*) FROM stockinfo WHERE \\\"Listing Exchange\\\" = 'P' AND ETF = 'Y';\"",
  "description": "Count NYSE Arca ETFs"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_stockmarket/query_dataset/stockinfo_query.db' \"SELECT Symbol FROM stockinfo WHERE \\\"Listing Exchange\\\" = 'P' AND ETF = 'Y';\" > /tmp/nyse_arca_etfs.txt && wc -l /tmp/nyse_arca_etfs.txt",
  "description": "Get list of NYSE Arca ETFs"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockmarket/query_dataset/stocktrade_query.db' \"SELECT table_name FROM information_schema.tables LIMIT 10;\"",
  "description": "Check tables in stocktrade"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockmarket/query_dataset/stocktrade_query.db' \"SELECT table_name FROM information_schema.tables;\" > /tmp/all_trade_tables.txt && wc -l /tmp/all_trade_tables.txt",
  "description": "Get all stocktrade tables"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_stockmarket/query_dataset/stocktrade_query.db' -csv -noheader \"SELECT table_name FROM information_schema.tables;\" > /tmp/all_trade_tables.txt && wc -l /tmp/all_trade_tables.txt",
  "description": "Get all stocktrade tables CSV"
}
